flow-diagram.createChart:
product -> { parts = $product == null ? list() : $product.get(`test.flowchart:Product#buildInstructions`);
nodes = $parts.map(p -> reactFlowSelection( userObject: $p, content: reactFlowBorder(stroke: "#eccf33", thickness: 2, cssClass: "tlSelectionMarker", content: reactFlowFill(fill: "#ffee95", cssClass: "tlSelectionMarker", content: reactFlowPadding(all: 3, content: reactFlowVertical( contents: [ $p.get(`test.flowchart:FlowNode#marker`).with(marker -> $marker.isEmpty() ? reactFlowEmpty() : reactFlowPadding(bottom: 8, content: reactFlowAlign( hAlign: "middle", content: reactFlowBorder( stroke: "red", dashes: [5, 5], content: reactFlowPadding( all: 4, content: reactFlowText($marker))))) ),
reactFlowAlign( hAlign: "middle", content: reactFlowPadding( all: 4, content: reactFlowText( fontWeight: "bold", text: $p.get(`test.flowchart:FlowNode#name`)) )),
reactFlowAlign( hAlign: "middle", content: reactFlowGrid( gapY: -1, contents: $p.get(`test.flowchart:FlowNode#locations`).map(l -> [ $l.get(`test.flowchart:Location#count`).with(count -> $count == null ? reactFlowEmpty() : reactFlowBorder( right: false, content: reactFlowPadding(all: 3, content: reactFlowText($count))) ), reactFlowBorder( content: reactFlowFill( fill: $l.get(`test.flowchart:Location#part`) .get(`test.flowchart:Part#color`), content: reactFlowPadding(all: 3, content: reactFlowText($l.get(`test.flowchart:Location#part`))) ) ), { usages = $l.get(`test.flowchart:Location#usages`); $usages.isEmpty() ? reactFlowEmpty() : reactFlowAlign( content: reactFlowBorder( left: false, content: reactFlowPadding(all: 3, content: reactFlowText($usages)))) } ]) )) ])))) ) );
nodeByPart = $nodes.indexBy(n -> $n["userObject"]);
$parts.isEmpty() ? reactFlowChart() : reactFlowChart( root: reactFlowPadding(all: 16, content: reactFlowTree( nodes: $nodes, connections: $parts .filter(p -> !$p.get(`test.flowchart:FlowNode#inputs`).isEmpty()) .map(p -> $p .get(`test.flowchart:FlowNode#inputs`) .map(c -> reactFlowConnection( parent: $nodeByPart[$p], child: $nodeByPart[$c]))) .flatten() ) ) ) }
